query:
CREATE TABLE IF NOT EXISTS `blockedDates` (`id` int AUTO_INCREMENT NOT NULL, `date` varchar(16) NOT NULL, `reason` varchar(256), `createdAt` timestamp NOT NULL DEFAULT (now()), CONSTRAINT `blockedDates_id` PRIMARY KEY(`id`));
CREATE TABLE IF NOT EXISTS `callTypes` (`id` int AUTO_INCREMENT NOT NULL, `name` varchar(256) NOT NULL, `slug` varchar(128) NOT NULL, `description` text, `durationMinutes` int NOT NULL DEFAULT 30, `price` decimal(10,2) DEFAULT '0', `currency` varchar(8) DEFAULT 'USD', `isActive` boolean NOT NULL DEFAULT true, `color` varchar(32) DEFAULT '#6366f1', `sortOrder` int DEFAULT 0, `createdAt` timestamp NOT NULL DEFAULT (now()), CONSTRAINT `callTypes_id` PRIMARY KEY(`id`), CONSTRAINT `callTypes_slug_unique` UNIQUE(`slug`));
CREATE TABLE IF NOT EXISTS `emailCaptures` (`id` int AUTO_INCREMENT NOT NULL, `email` varchar(320) NOT NULL, `firstName` varchar(128), `source` varchar(128) DEFAULT 'book_download', `createdAt` timestamp NOT NULL DEFAULT (now()), CONSTRAINT `emailCaptures_id` PRIMARY KEY(`id`));
CREATE TABLE IF NOT EXISTS `leads` (`id` int AUTO_INCREMENT NOT NULL, `firstName` varchar(128) NOT NULL, `lastName` varchar(128) NOT NULL, `email` varchar(320) NOT NULL, `phone` varchar(32), `company` varchar(256), `jobTitle` varchar(256), `website` varchar(512), `linkedIn` varchar(512), `stage` enum('new_lead','contacted','qualified','proposal_sent','closed_won','closed_lost') NOT NULL DEFAULT 'new_lead', `source` enum('website_contact','book_download','booking','referral','linkedin','other') NOT NULL DEFAULT 'website_contact', `dealValue` decimal(12,2), `offerInterest` enum('sprint','advisory','both','unknown') NOT NULL DEFAULT 'unknown', `notes` text, `tags` json DEFAULT ('[]'), `isArchived` boolean NOT NULL DEFAULT false, `createdAt` timestamp NOT NULL DEFAULT (now()), `updatedAt` timestamp NOT NULL DEFAULT (now()) ON UPDATE CURRENT_TIMESTAMP, `lastContactedAt` timestamp, CONSTRAINT `leads_id` PRIMARY KEY(`id`));
CREATE TABLE IF NOT EXISTS `interactions` (`id` int AUTO_INCREMENT NOT NULL, `leadId` int NOT NULL, `type` enum('note','email','call','meeting','booking','stage_change','system') NOT NULL, `title` varchar(512) NOT NULL, `body` text, `metadata` json, `createdAt` timestamp NOT NULL DEFAULT (now()), CONSTRAINT `interactions_id` PRIMARY KEY(`id`));
CREATE TABLE IF NOT EXISTS `bookings` (`id` int AUTO_INCREMENT NOT NULL, `callTypeId` int NOT NULL, `leadId` int, `firstName` varchar(128) NOT NULL, `lastName` varchar(128) NOT NULL, `email` varchar(320) NOT NULL, `phone` varchar(32), `company` varchar(256), `message` text, `scheduledDate` varchar(16) NOT NULL, `scheduledTime` varchar(8) NOT NULL, `timezone` varchar(64) DEFAULT 'America/Los_Angeles', `status` enum('pending','confirmed','cancelled','completed') NOT NULL DEFAULT 'pending', `confirmationToken` varchar(128), `adminNotes` text, `createdAt` timestamp NOT NULL DEFAULT (now()), `updatedAt` timestamp NOT NULL DEFAULT (now()) ON UPDATE CURRENT_TIMESTAMP, CONSTRAINT `bookings_id` PRIMARY KEY(`id`));

